  7‚Üí
  8‚Üíimport kotlinx.datetime.internal.POWERS_OF_TEN
  9‚Üíimport kotlinx.datetime.internal.DecimalFraction
 10‚Üí
 11‚Üí/**
 12‚Üí * A parser that expects to receive a string consisting of [length] digits, or, if [length] is `null`,
 13‚Üí * a string consisting of any number of digits.
 14‚Üí */
 15‚Üíinternal sealed class NumberConsumer<in Receiver>(
 16‚Üí    /** The number of digits to consume. `null` means that the length is variable. */
 17‚Üí    open val length: Int?,
 18‚Üí    /** The human-readable name of the entity being parsed here. */
 19‚Üí    val whatThisExpects: String
 20‚Üí) {
 21‚Üí    /**
 22‚Üí     * Wholly consumes the given [input]. Should be called with a string consisting of [length] digits, or,
 23‚Üí     * if [length] is `null`, with a string consisting of any number of digits. [consume] itself does not
 24‚Üí     * necessarily check the length of the input string, instead expecting to be passed a valid one.
 25‚Üí     *
 26‚Üí     * Returns `null` on success and a `NumberConsumptionError` on failure.
 27‚Üí     */
 28‚Üí    abstract fun consume(storage: Receiver, input: String): NumberConsumptionError?
 29‚Üí}
 30‚Üí
 31‚Üíinternal interface NumberConsumptionError {
 32‚Üí    fun errorMessage(): String
 33‚Üí    object ExpectedInt: NumberConsumptionError {
 34‚Üí        override fun errorMessage() = "expected an Int value"
 35‚Üí    }
 36‚Üí    class TooManyDigits(val maxDigits: Int): NumberConsumptionError {
 37‚Üí        override fun errorMessage() = "expected at most $maxDigits digits"
 38‚Üí    }
 39‚Üí    class TooFewDigits(val minDigits: Int): NumberConsumptionError {
 40‚Üí        override fun errorMessage() = "expected at least $minDigits digits"
 41‚Üí    }
 42‚Üí    class WrongConstant(val expected: String): NumberConsumptionError {
 43‚Üí        override fun errorMessage() = "expected '$expected'"
 44‚Üí    }
 45‚Üí    class Conflicting(val conflicting: Any): NumberConsumptionError {
 46‚Üí        override fun errorMessage() = "attempted to overwrite the existing value '$conflicting'"
 47‚Üí    }
 48‚Üí}
 49‚Üí
 50‚Üí/**
 51‚Üí * A parser that accepts an [Int] value in range from `0` to [Int.MAX_VALUE].
 52‚Üí */
 53‚Üí// TODO: should the parser reject excessive padding?
 54‚Üíinternal class UnsignedIntConsumer<in Receiver>(
 55‚Üí    private val minLength: Int?,
 56‚Üí    private val maxLength: Int?,
 57‚Üí    private val setter: AssignableField<Receiver, Int>,
 58‚Üí    name: String,
 59‚Üí    private val multiplyByMinus1: Boolean = false,
 60‚Üí) : NumberConsumer<Receiver>(if (minLength == maxLength) minLength else null, name) {
 61‚Üí
 62‚Üí    init {
 63‚Üí        require(length == null || length in 1..9) { "Invalid length for field $whatThisExpects: $length" }
 64‚Üí    }
 65‚Üí
 66‚Üí    override fun consume(storage: Receiver, input: String): NumberConsumptionError? = when {
 67‚Üí        maxLength != null && input.length > maxLength -> NumberConsumptionError.TooManyDigits(maxLength)
 68‚Üí        minLength != null && input.length < minLength -> NumberConsumptionError.TooFewDigits(minLength)
 69‚Üí        else -> when (val result = input.toIntOrNull()) {
 70‚Üí            null -> NumberConsumptionError.ExpectedInt
 71‚Üí            else -> setter.setWithoutReassigning(storage, if (multiplyByMinus1) -result else result)
 72‚Üí        }
 73‚Üí    }
 74‚Üí}
 75‚Üí
 76‚Üíinternal class ReducedIntConsumer<in Receiver>(
 77‚Üí    override val length: Int,
 78‚Üí    private val setter: AssignableField<Receiver, Int>,
 79‚Üí    name: String,
 80‚Üí    val base: Int,
 81‚Üí): NumberConsumer<Receiver>(length, name) {
 82‚Üí
 83‚Üí    private val modulo = POWERS_OF_TEN[length]
 84‚Üí    private val baseMod = base % modulo
 85‚Üí    private val baseFloor = base - baseMod
 86‚Üí
 87‚Üí    override fun consume(storage: Receiver, input: String): NumberConsumptionError? = when (val result = input.toIntOrNull()) {
 88‚Üí        null -> NumberConsumptionError.ExpectedInt
 89‚Üí        else -> setter.setWithoutReassigning(storage, if (result >= baseMod) {
 90‚Üí            baseFloor + result
 91‚Üí        } else {
 92‚Üí            baseFloor + modulo + result
 93‚Üí        })
 94‚Üí    }
 95‚Üí}
 96‚Üí
 97‚Üí/**
 98‚Üí * A parser that consumes exactly the string [expected].
 99‚Üí */
100‚Üíinternal class ConstantNumberConsumer<in Receiver>(
101‚Üí    private val expected: String
102‚Üí) : NumberConsumer<Receiver>(expected.length, "the predefined string $expected") {
103‚Üí    override fun consume(storage: Receiver, input: String): NumberConsumptionError? = if (input == expected) {
104‚Üí        null
105‚Üí    } else {
106‚Üí        NumberConsumptionError.WrongConstant(expected)
107‚Üí    }
108‚Üí}
109‚Üí
110‚Üíinternal class FractionPartConsumer<in Receiver>(
111‚Üí    private val minLength: Int?,
112‚Üí    private val maxLength: Int?,
113‚Üí    private val setter: AssignableField<Receiver, DecimalFraction>,
114‚Üí    name: String,
115‚Üí) : NumberConsumer<Receiver>(if (minLength == maxLength) minLength else null, name) {
116‚Üí    init {
117‚Üí        require(minLength == null || minLength in 1..9) { "Invalid length for field $whatThisExpects: $length" }
118‚Üí        // TODO: bounds on maxLength
119‚Üí    }
120‚Üí
121‚Üí    override fun consume(storage: Receiver, input: String): NumberConsumptionError? = when {
122‚Üí        minLength != null && input.length < minLength -> NumberConsumptionError.TooFewDigits(minLength)
123‚Üí        maxLength != null && input.length > maxLength -> NumberConsumptionError.TooManyDigits(maxLength)
124‚Üí        else -> when (val numerator = input.toIntOrNull()) {
125‚Üí            null -> NumberConsumptionError.TooManyDigits(9)
126‚Üí            else -> setter.setWithoutReassigning(storage, DecimalFraction(numerator, input.length))
127‚Üí        }
128‚Üí    }
129‚Üí}
