217‚Üíinternal sealed interface NonConcatenatedFormatStructure<in T> : FormatStructure<T>
218‚Üí
219‚Üíinternal open class ConcatenatedFormatStructure<in T>(
220‚Üí    val formats: List<NonConcatenatedFormatStructure<T>>
221‚Üí) : FormatStructure<T> {
222‚Üí    override fun toString(): String = "ConcatenatedFormatStructure(${formats.joinToString(", ")})"
223‚Üí
224‚Üí    override fun equals(other: Any?): Boolean = other is ConcatenatedFormatStructure<*> && formats == other.formats
225‚Üí
226‚Üí    override fun hashCode(): Int = formats.hashCode()
227‚Üí
228‚Üí    override fun parser(): ParserStructure<T> = formats.map { it.parser() }.concat()
229‚Üí
230‚Üí    override fun formatter(): FormatterStructure<T> {
231‚Üí        val formatters = formats.map { it.formatter() }
232‚Üí        return if (formatters.size == 1) {
233‚Üí            formatters.single()
234‚Üí        } else {
235‚Üí            ConcatenatedFormatter(formatters)
236‚Üí        }
237‚Üí    }
238‚Üí}
