131‚Üíprivate fun <Object, Type> AssignableField<Object, Type>.setWithoutReassigning(
132‚Üí    receiver: Object,
133‚Üí    value: Type,
134‚Üí): NumberConsumptionError? {
135‚Üí    val conflictingValue = trySetWithoutReassigning(receiver, value) ?: return null
136‚Üí    return NumberConsumptionError.Conflicting(conflictingValue)
137‚Üí}
