 20‚Üíinternal class UnsignedIntFormatterStructure<in T>(
 21‚Üí    private val number: (T) -> Int,
 22‚Üí    private val zeroPadding: Int,
 23‚Üí): FormatterStructure<T> {
 24‚Üí
 25‚Üí    init {
 26‚Üí        require(zeroPadding >= 0) { "The minimum number of digits ($zeroPadding) is negative" }
 27‚Üí        require(zeroPadding <= 9) { "The minimum number of digits ($zeroPadding) exceeds the length of an Int" }
