 38‚Üíinternal class SignedIntFormatterStructure<in T>(
 39‚Üí    private val number: (T) -> Int,
 40‚Üí    private val zeroPadding: Int,
 41‚Üí    private val outputPlusOnExceededWidth: Int?,
 42‚Üí): FormatterStructure<T> {
 43‚Üí
 44‚Üí    init {
 45‚Üí        require(zeroPadding >= 0) { "The minimum number of digits ($zeroPadding) is negative" }
 46‚Üí        require(zeroPadding <= 9) { "The minimum number of digits ($zeroPadding) exceeds the length of an Int" }
 47‚Üí    }
 48‚Üí
 49‚Üí    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
 50‚Üí        val innerBuilder = StringBuilder()
 51‚Üí        val number = number(obj).let { if (minusNotRequired && it < 0) -it else it }
 52‚Üí        if (outputPlusOnExceededWidth != null && number >= POWERS_OF_TEN[outputPlusOnExceededWidth]) {
 53‚Üí            innerBuilder.append('+')
 54‚Üí        }
 55‚Üí        if (number.absoluteValue < POWERS_OF_TEN[zeroPadding - 1]) {
 56‚Üí            // needs padding
 57‚Üí            if (number >= 0) {
 58‚Üí                innerBuilder.append((number + POWERS_OF_TEN[zeroPadding])).deleteAt(0)
 59‚Üí            } else {
 60‚Üí                innerBuilder.append((number - POWERS_OF_TEN[zeroPadding])).deleteAt(1)
 61‚Üí            }
 62‚Üí        } else {
 63‚Üí            innerBuilder.append(number)
 64‚Üí        }
 65‚Üí        builder.append(innerBuilder)
 66‚Üí    }
 67‚Üí}
