104‚Üíinternal class StringFormatterStructure<in T>(
105‚Üí    private val string: (T) -> String,
106‚Üí): FormatterStructure<T> {
107‚Üí    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
108‚Üí        builder.append(string(obj))
109‚Üí    }
