110‚Üíinternal class FractionPartConsumer<in Receiver>(
111‚Üí    private val minLength: Int?,
112‚Üí    private val maxLength: Int?,
113‚Üí    private val setter: AssignableField<Receiver, DecimalFraction>,
114‚Üí    name: String,
115‚Üí) : NumberConsumer<Receiver>(if (minLength == maxLength) minLength else null, name) {
116‚Üí    init {
117‚Üí        require(minLength == null || minLength in 1..9) { "Invalid length for field $whatThisExpects: $length" }
118‚Üí        // TODO: bounds on maxLength
119‚Üí    }
120‚Üí
121‚Üí    override fun consume(storage: Receiver, input: String): NumberConsumptionError? = when {
122‚Üí        minLength != null && input.length < minLength -> NumberConsumptionError.TooFewDigits(minLength)
123‚Üí        maxLength != null && input.length > maxLength -> NumberConsumptionError.TooManyDigits(maxLength)
124‚Üí        else -> when (val numerator = input.toIntOrNull()) {
125‚Üí            null -> NumberConsumptionError.TooManyDigits(9)
126‚Üí            else -> setter.setWithoutReassigning(storage, DecimalFraction(numerator, input.length))
127‚Üí        }
128‚Üí    }
129‚Üí}
