 69‚Üíinternal class DecimalFractionFormatterStructure<in T>(
 70‚Üí    private val number: (T) -> DecimalFraction,
 71‚Üí    private val minDigits: Int,
 72‚Üí    private val maxDigits: Int,
 73‚Üí    private val zerosToAdd: List<Int>,
 74‚Üí): FormatterStructure<T> {
 75‚Üí
 76‚Üí    init {
 77‚Üí        require(minDigits in 1..9) {
 78‚Üí            "The minimum number of digits ($minDigits) is not in range 1..9"
 79‚Üí        }
 80‚Üí        require(maxDigits in minDigits..9) {
 81‚Üí            "The maximum number of digits ($maxDigits) is not in range $minDigits..9"
 82‚Üí        }
 83‚Üí    }
 84‚Üí
 85‚Üí    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
 86‚Üí        val number = number(obj)
 87‚Üí        // round the number to `maxDigits` significant figures
 88‚Üí        val numberWithRequiredPrecision = number.fractionalPartWithNDigits(maxDigits)
 89‚Üí        // we strip away trailing zeros while we can
 90‚Üí        var zerosToStrip = 0
 91‚Üí        while (maxDigits > minDigits + zerosToStrip && numberWithRequiredPrecision % POWERS_OF_TEN[zerosToStrip + 1] == 0) {
 92‚Üí            ++zerosToStrip
 93‚Üí        }
 94‚Üí        // we add some zeros back if it means making the number that's being output prettier, like `.01` becoming `.010`
 95‚Üí        val zerosToAddBack = zerosToAdd[maxDigits - zerosToStrip - 1]
 96‚Üí        if (zerosToStrip >= zerosToAddBack) zerosToStrip -= zerosToAddBack
 97‚Üí        // the final stage of outputting the number
 98‚Üí        val digitsToOutput = maxDigits - zerosToStrip
 99‚Üí        val numberToOutput = numberWithRequiredPrecision / POWERS_OF_TEN[zerosToStrip]
100‚Üí        builder.append((numberToOutput + POWERS_OF_TEN[digitsToOutput]).toString().substring(1))
101‚Üí    }
102‚Üí}
103‚Üí
104‚Üíinternal class StringFormatterStructure<in T>(
105‚Üí    private val string: (T) -> String,
106‚Üí): FormatterStructure<T> {
107‚Üí    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
108‚Üí        builder.append(string(obj))
109‚Üí    }
110‚Üí}
