112‚Üíinternal class ReducedIntFormatterStructure<in T>(
113‚Üí    private val number: (T) -> Int,
114‚Üí    private val digits: Int,
115‚Üí    private val base: Int,
116‚Üí): FormatterStructure<T> {
117‚Üí    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
118‚Üí        val number = number(obj)
119‚Üí        if (number - base in 0 until POWERS_OF_TEN[digits]) {
120‚Üí            // the number fits
121‚Üí            val numberStr = (number % POWERS_OF_TEN[digits]).toString()
122‚Üí            val zeroPaddingStr = '0'.toString().repeat(maxOf(0, digits - numberStr.length))
123‚Üí            builder.append(zeroPaddingStr, numberStr)
124‚Üí        } else {
125‚Üí            if (number >= 0)
126‚Üí                builder.append("+")
127‚Üí            builder.append(number.toString())
128‚Üí        }
129‚Üí    }
130‚Üí}
