 71‚Üí// https://datatracker.ietf.org/doc/html/rfc8536
 72‚Üíinternal fun readTzFile(data: ByteArray): TzFile {
 73‚Üí    class Header(
 74‚Üí        val version: Int?,
 75‚Üí        val ttisutcnt: Int,
 76‚Üí        val ttisstdcnt: Int,
 77‚Üí        val leapcnt: Int,
 78‚Üí        val timecnt: Int,
 79‚Üí        val typecnt: Int,
 80‚Üí        val charcnt: Int
 81‚Üí    ) {
 82‚Üí        override fun toString(): String = "Header(version=$version, ttisutcnt=$ttisutcnt, ttisstdcnt=$ttisstdcnt, " +
 83‚Üí            "leapcnt=$leapcnt, timecnt=$timecnt, typecnt=$typecnt, charcnt=$charcnt)"
 84‚Üí    }
 85‚Üí
 86‚Üí    class Ttinfo(val utoff: Int, val isdst: Boolean, val abbrind: UByte) {
 87‚Üí        override fun toString(): String = "Ttinfo(utoff=$utoff, isdst=$isdst, abbrind=$abbrind)"
 88‚Üí    }
 89‚Üí
 90‚Üí    inline fun BinaryDataReader.readData(header: Header, readTime: () -> Long): TzFileData {
 91‚Üí        val transitionTimes = List(header.timecnt) { readTime() }
 92‚Üí        val transitionTypes = List(header.timecnt) { readByte() }
 93‚Üí        val ttinfos = List(header.typecnt) {
 94‚Üí            Ttinfo(
 95‚Üí                readInt(),
 96‚Üí                readByte() != 0.toByte(),
 97‚Üí                readUnsignedByte()
 98‚Üí            )
 99‚Üí        }
100‚Üí        val abbreviations = List(header.charcnt) { readByte() }
101‚Üí        fun abbreviationForIndex(startIndex: UByte): String = abbreviations.drop(startIndex.toInt())
102‚Üí            .takeWhile { byte -> byte != 0.toByte() }.toByteArray().decodeToString()
103‚Üí        val leapSecondRules = List(header.leapcnt) {
104‚Üí            TzFileData.LeapSecondRule(
105‚Üí                readTime(),
106‚Üí                readInt()
107‚Üí            )
108‚Üí        }
109‚Üí        // The following fields are not used in practice. See https://datatracker.ietf.org/doc/html/rfc8536#section-3.2,
110‚Üí        // near the end of the section, `A given pair of standard/wall and UT/local indicators...`
111‚Üí        repeat(header.ttisstdcnt) { readByte() }
112‚Üí        repeat(header.ttisutcnt) { readByte() }
113‚Üí        return TzFileData(
114‚Üí            leapSecondRules,
115‚Üí            transitionTimes.zip(transitionTypes) { time, type -> TzFileData.Transition(time, type.toInt()) },
116‚Üí            ttinfos.map { TzFileData.ClockState(TzFileOffset(it.utoff), it.isdst, abbreviationForIndex(it.abbrind)) }
117‚Üí        )
118‚Üí    }
119‚Üí
120‚Üí    fun BinaryDataReader.read32BitData(header: Header): TzFileData = readData(header) { readInt().toLong() }
121‚Üí
122‚Üí    fun BinaryDataReader.read64BitData(header: Header): TzFileData = readData(header) { readLong() }
123‚Üí
124‚Üí    inline fun BinaryDataReader.readFooter() = check(readByte() == '\n'.code.toByte()).let {
125‚Üí        PosixTzString.readIfPresent(this)
126‚Üí    }
127‚Üí
128‚Üí    val reader = BinaryDataReader(data)
129‚Üí
130‚Üí    fun readHeader(): Header {
131‚Üí        val magic = reader.readUtf8String(4)
132‚Üí        check(magic == "TZif") { "Invalid tzfile magic: '$magic', expected 'TZif'" }
133‚Üí        val version = when (reader.readByte()) {
134‚Üí            0.toByte() -> 1
135‚Üí            0x32.toByte() -> 2
136‚Üí            0x33.toByte() -> 3
137‚Üí            else -> null
138‚Üí        }
139‚Üí        reader.skip(15)
140‚Üí        return Header(
141‚Üí            version,
142‚Üí            reader.readInt(),
143‚Üí            reader.readInt(),
144‚Üí            reader.readInt(),
145‚Üí            reader.readInt(),
146‚Üí            reader.readInt(),
147‚Üí            reader.readInt()
148‚Üí        ).also {
149‚Üí            check(it.ttisutcnt == 0 || it.ttisutcnt == it.typecnt)
150‚Üí            check(it.ttisstdcnt == 0 || it.ttisstdcnt == it.typecnt)
151‚Üí        }
152‚Üí    }
153‚Üí
154‚Üí    val header = readHeader()
155‚Üí    return when (header.version) {
156‚Üí        1 -> {
157‚Üí            TzFile(reader.read32BitData(header), null)
158‚Üí        }
159‚Üí        else -> {
160‚Üí            reader.read32BitData(header) // skipped
161‚Üí            val newHeader = readHeader()
162‚Üí            val parsedData = reader.read64BitData(newHeader)
163‚Üí            val footer = reader.readFooter()
164‚Üí            TzFile(parsedData, footer)
165‚Üí        }
166‚Üí    }
167‚Üí}
