169‚Üíinternal class PosixTzString(
170‚Üí    private val standardTime: Pair<String, UtcOffset>,
171‚Üí    private val daylightTime: Pair<String, UtcOffset>?,
172‚Üí    private val rules: Pair<MonthDayTime, MonthDayTime>?,
173‚Üí) {
174‚Üí    companion object {
175‚Üí        /**
176‚Üí         * Reads a POSIX TZ string from the [reader] if it is present, or returns `null` if it is not.
177‚Üí         *
178‚Üí         * The string format is described in https://pubs.opengroup.org/onlinepubs/9699919799/, section 8.3,
179‚Üí         * with additional extensions in https://datatracker.ietf.org/doc/html/rfc8536#section-3.3.1
180‚Üí         *
181‚Üí         * @throws IllegalArgumentException if the string is invalid
182‚Üí         * @throws IllegalStateException if the string is invalid
183‚Üí         */
184‚Üí        fun readIfPresent(reader: BinaryDataReader): PosixTzString? = reader.readPosixTzString()
185‚Üí    }
186‚Üí
187‚Üí    fun toRecurringZoneRules(): RecurringZoneRules? {
188‚Üí        /**
189‚Üí         * In theory, it's possible to have a DST transition but no start/end date.
190‚Üí         * In this case, the behavior is not specified, and on Linux, the rules for America/New_York are used
191‚Üí         * to determine the start/end dates (see `tzset(3)`, search for `posixrules`).
192‚Üí         * The <https://github.com/HowardHinnant/date> library takes the lack of start/end dates
193‚Üí         * to mean that the standard offset is always in effect, which seems to be a much more reasonable interpretation.
194‚Üí         */
195‚Üí        if (daylightTime == null || rules == null) return null
196‚Üí        val (start, end) = rules
197‚Üí        val rule1 = RecurringZoneRules.Rule(start, standardTime.second, daylightTime.second)
198‚Üí        val rule2 = RecurringZoneRules.Rule(end, daylightTime.second, standardTime.second)
199‚Üí        return RecurringZoneRules(listOf(rule1, rule2))
200‚Üí    }
201‚Üí}
202‚Üíprivate fun BinaryDataReader.readPosixTzString(): PosixTzString? {
203‚Üí    var c = readAsciiChar()
204‚Üí    fun readName(): String? {
205‚Üí        if (c == '\n') return null
206‚Üí        val name = StringBuilder()
207‚Üí        if (c == '<') {
208‚Üí            c = readAsciiChar()
209‚Üí            while (c != '>') {
210‚Üí                check(c.isLetterOrDigit() || c == '-' || c == '+') { "Invalid char '$c' in the std name in POSIX TZ string" }
211‚Üí                name.append(c)
212‚Üí                c = readAsciiChar()
213‚Üí            }
214‚Üí            c = readAsciiChar()
215‚Üí        } else {
216‚Üí            while (c.isLetter()) {
217‚Üí                name.append(c)
218‚Üí                c = readAsciiChar()
219‚Üí            }
220‚Üí        }
221‚Üí        check(name.isNotEmpty()) { "Empty std name in POSIX TZ string" }
222‚Üí        return name.toString()
223‚Üí    }
224‚Üí
225‚Üí    fun readOffset(): UtcOffset? {
226‚Üí        if (c == '\n') return null
227‚Üí        val offsetIsNegative: Boolean
228‚Üí        when (c) {
229‚Üí            '-' -> {
230‚Üí                offsetIsNegative = true
231‚Üí                c = readAsciiChar()
232‚Üí            }
233‚Üí
234‚Üí            '+' -> {
235‚Üí                offsetIsNegative = false
236‚Üí                c = readAsciiChar()
237‚Üí            }
238‚Üí
239‚Üí            else -> {
240‚Üí                if (!c.isDigit()) return null
241‚Üí                offsetIsNegative = false
242‚Üí            }
243‚Üí        }
244‚Üí        val sign = if (offsetIsNegative) 1 else -1 // not a typo: the sign is inverted in the rules
245‚Üí        var hours = c.digitToInt()
246‚Üí        c = readAsciiChar()
247‚Üí        if (c.isDigit()) {
248‚Üí            hours = hours * 10 + c.digitToInt()
249‚Üí            c = readAsciiChar()
250‚Üí        }
251‚Üí        if (c != ':') return UtcOffset(sign * hours)
252‚Üí        val minutes = readAsciiChar().digitToInt() * 10 + readAsciiChar().digitToInt()
253‚Üí        c = readAsciiChar()
254‚Üí        if (c != ':') return UtcOffset(sign * hours, sign * minutes)
255‚Üí        val seconds = readAsciiChar().digitToInt() * 10 + readAsciiChar().digitToInt()
256‚Üí        c = readAsciiChar()
257‚Üí        return UtcOffset(sign * hours, sign * minutes, sign * seconds)
258‚Üí    }
259‚Üí
260‚Üí    fun readDate(): DateOfYear? {
261‚Üí        if (c == '\n') return null
262‚Üí        check(c == ',') { "Invalid char '$c' in POSIX TZ string after the DST offset" }
263‚Üí        c = readAsciiChar()
264‚Üí        return when (c) {
265‚Üí            'J' -> {
266‚Üí                c = readAsciiChar()
267‚Üí                var result = 0
268‚Üí                while (c.isDigit()) {
269‚Üí                    result = result * 10 + c.digitToInt()
270‚Üí                    c = readAsciiChar()
271‚Üí                }
272‚Üí                JulianDayOfYearSkippingLeapDate(result)
273‚Üí            }
274‚Üí            'M' -> {
275‚Üí                c = readAsciiChar()
276‚Üí                var month = c.digitToInt()
